const cp = require('child_process');
const fs = require('fs');
const input = $input.first().json;
const message = (input.params && input.params.message) || input.message || 'No message';
let chatId = (input.params && input.params.chat_id) || input.chat_id || '';
let botToken = (input.params && input.params.bot_token) || input.bot_token || '';

// Read from .env if not provided
if (!chatId || !botToken) {
  try {
    const env = fs.readFileSync('__PROJECT_ROOT__/.env', 'utf8');
    if (!chatId) chatId = (env.match(/TELEGRAM_CHAT_ID=(.+)/) || [])[1] || '';
    if (!botToken) botToken = (env.match(/TELEGRAM_BOT_TOKEN=(.+)/) || [])[1] || '';
  } catch {}
}

if (!chatId || !botToken) {
  return [{json: {status: 'error', error: 'Missing TELEGRAM_CHAT_ID or TELEGRAM_BOT_TOKEN'}}];
}

try {
  const url = 'https://api.telegram.org/bot' + botToken.trim() + '/sendMessage';
  const body = JSON.stringify({chat_id: chatId.trim(), text: message.substring(0, 4000), parse_mode: 'Markdown'});
  cp.execSync('curl -s -X POST "' + url + '" -H "Content-Type: application/json" -d ' + JSON.stringify(body).replace(/"/g, '\\"'), {timeout: 10000, encoding: 'utf8'});
  return [{json: {status: 'sent', chat_id: chatId, length: message.length, timestamp: new Date().toISOString()}}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
